// ❌ BAD - silent overflow in financial calculation
int totalItemsSold = int.MaxValue;
int newSales = 1;
int updatedTotal = totalItemsSold + newSales; // silently wraps to -2147483648
Console.WriteLine(updatedTotal); // -2147483648 - wrong result, no exception

// ✅ GOOD - use checked to catch overflow
int updatedTotal2 = checked(totalItemsSold + newSales); // throws OverflowException
// Or use long for large counters
long safeTotal = (long)totalItemsSold + newSales;

// ❌ BAD - assuming all return values are aggregated
Func<decimal, decimal> applyDiscount = price => price * 0.9m;  // 10% off
applyDiscount += price => price * 0.85m; // 15% off
applyDiscount += price => price * 0.8m;  // 20% off
decimal result = applyDiscount(100m);
Console.WriteLine(result); // 80 - only the last lambda ran effectively

// ✅ GOOD - collect all results individually via GetInvocationList
var results = applyDiscount.GetInvocationList()
    .Select(d => ((Func<decimal, decimal>)d)(100m))
    .ToList();
// results = [90, 85, 80]

// ❌ BAD - assuming cast rounds to nearest integer
double orderTotal = 29.99;
int taxUnits = (int)(orderTotal * 0.1); // truncates 2.999 to 2, not 3
Console.WriteLine(taxUnits); // 2 - may undercharge tax

// ✅ GOOD - use Math.Round when nearest-integer semantics are needed
int taxUnitsRounded = (int)Math.Round(orderTotal * 0.1); // rounds 2.999 to 3
Console.WriteLine(taxUnitsRounded); // 3

// ❌ BAD - developer assumes ?? treats 0 as null
int? userPreferredPageSize = 0;
int pageSize = userPreferredPageSize ?? 20;
Console.WriteLine(pageSize); // 0 - NOT 20 because 0 is not null

// ✅ GOOD - use explicit check if 0 should also fall back
int pageSize2 = (userPreferredPageSize == null || userPreferredPageSize == 0)
    ? 20
    : userPreferredPageSize.Value;
Console.WriteLine(pageSize2); // 20

// ❌ BAD - releasing a resource only inside try (missed on exception)
SqlConnection conn = new SqlConnection(connectionString);
try
{
    conn.Open();
    // do work
    conn.Close(); // skipped if an exception occurs above
}
catch { Console.WriteLine("Error"); }

// ✅ GOOD - release in finally to guarantee cleanup
try
{
    conn.Open();
    // do work
}
catch { Console.WriteLine("Error"); }
finally { conn.Close(); } // always runs

// ❌ BAD - assuming outer catch runs before inner cleanup
void ProcessPayment()
{
    DbTransaction tx = null;
    try
    {
        try
        {
            tx = db.BeginTransaction();
            // operation throws
        }
        finally
        {
            tx?.Rollback(); // this runs FIRST on exception
        }
    }
    catch (Exception ex)
    {
        LogError(ex); // this runs SECOND
    }
}

// ✅ GOOD - correct and expected: rollback before the error is logged

// ❌ BAD - assuming async code runs completely before returning
async Task SendOrderConfirmation(Order order)
{
    Console.WriteLine("Sending");
    await emailService.SendAsync(order.Email, order.Details);
    Console.WriteLine("Sent"); // may print MUCH later
}
SendOrderConfirmation(order); // fire and forget - no await
Console.WriteLine("Order processed"); // prints BEFORE 'Sent'

// ✅ GOOD - await the async call to get predictable ordering
await SendOrderConfirmation(order);
Console.WriteLine("Order processed"); // prints AFTER 'Sent'

// ❌ BAD - referencing a static field in another field's initializer before it is set
class Config
{
    static string DefaultRegion = Environment.GetEnvironmentVariable("REGION") ?? "EU";
    static string FullEndpoint = BaseUrl + "/api"; // BaseUrl is null here - set later
    static string BaseUrl = "https://api.payments.com";
}

// ✅ GOOD - declare in dependency order so each initializer sees already-set fields
class Config
{
    static string BaseUrl = "https://api.payments.com";
    static string FullEndpoint = BaseUrl + "/api"; // BaseUrl is set above - safe
}

// ❌ BAD - no null guard in params method
void LogEvents(params string[] events)
{
    Console.WriteLine(events.Length); // NRE if called with null
}
LogEvents(null); // NullReferenceException

// ✅ GOOD - guard against null params argument
void LogEvents(params string[] events)
{
    if (events == null) return;
    Console.WriteLine(events.Length);
}
LogEvents();      // prints 0
LogEvents(null);  // safely returns without error

// ❌ BAD - trying to assign List<Dog> to List<Animal> (compile error)
List<Dog> dogs = new List<Dog> { new Dog() };
List<Animal> animals = dogs; // CS0029: Cannot implicitly convert List<Dog> to List<Animal>

// ✅ GOOD - use IEnumerable<Animal> which is covariant
IEnumerable<Dog> dogs2 = new List<Dog> { new Dog() };
IEnumerable<Animal> animals2 = dogs2; // legal - IEnumerable is covariant
Console.WriteLine(animals2.Count()); // 1
